<?php
namespace Tests\Feature;
use App\Domain\Characters\Actions\CreateCharacterAction;use App\Domain\Characters\Accounts\CharacterAccountLimit;use App\Domain\Media\MediaAssetType;use App\Models\Character;use App\Models\CharacterClass;use App\Models\CharacterTemplate;use App\Models\User;use Database\Seeders\CharacterLevelRequirementSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\Storage;use Illuminate\Validation\ValidationException;use Tests\TestCase;
class CharacterAccountTest extends TestCase{use RefreshDatabase;private $template;protected function setUp():void{parent::setUp();$this->seed(CharacterLevelRequirementSeeder::class);Storage::fake('public');$class=CharacterClass::where('code','adventurer')->firstOrFail();$this->template=CharacterTemplate::factory()->create(['character_class_id'=>$class->id,'presentation_gender'=>'male','status'=>'active']);$variants=[];foreach([128,256,512]as$size){$variants[(string)$size]='accounts/'.$size.'.webp';Storage::disk('public')->put($variants[(string)$size],'x');}$this->template->mediaAssets()->create(['asset_type'=>MediaAssetType::BASE_VISUAL,'disk'=>'public','path'=>$variants['256'],'mime_type'=>'image/webp','width'=>256,'height'=>384,'file_size'=>1,'is_primary'=>true,'metadata'=>['character_visual_version'=>1,'root'=>'accounts','body_type'=>$this->template->body_type,'canvas'=>['width'=>512,'height'=>768,'ratio'=>'2:3'],'variants'=>$variants]]);}public function test_zero_one_two_can_create_and_three_cannot(){$action=app(CreateCharacterAction::class);foreach([0,1,2]as$count){$user=User::factory()->create();for($i=0;$i<$count;$i++)Character::factory()->for($user)->create(['name'=>'Previo '.$count.' '.$i]);$this->assertTrue($user->can('create',Character::class));$action->execute($user,'Heroe '.$count,$this->template->id);}$full=User::factory()->create();Character::factory()->for($full)->count(CharacterAccountLimit::MAX_CHARACTERS)->create();$this->assertFalse($full->can('create',Character::class));$this->expectException(ValidationException::class);$action->execute($full,'Cuarto Heroe',$this->template->id);}public function test_names_are_normalized_reserved_numeric_and_accent_insensitive(){$action=app(CreateCharacterAction::class);$first=$action->execute(User::factory()->create(),'  José   Luna  ',$this->template->id);$this->assertSame('José Luna',$first->name);$this->assertSame('josé luna',$first->normalized_name);foreach(['admin','12345']as$name){try{$action->execute(User::factory()->create(),$name,$this->template->id);$this->fail('Nombre inválido aceptado.');}catch(ValidationException $e){$this->assertTrue(true);}}$this->expectException(ValidationException::class);$action->execute(User::factory()->create(),'JOSE LUNA',$this->template->id);}public function test_creation_copies_template_and_selects_new_character(){$user=User::factory()->create();$character=app(CreateCharacterAction::class)->execute($user,'Nueva Heroina',$this->template->id);$this->assertSame($character->id,$user->fresh()->active_character_id);$this->assertSame($this->template->character_class_id,$character->character_class_id);$this->assertSame($this->template->id,$character->character_template_id);}}
